<?php
namespace Tests\Feature\Hr;use App\Models\HrLicense;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Core\Services\TenantContext;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class WorkforcePlanningPagesTest extends TestCase{use RefreshHrDatabase;public function test_page_renders_with_analytics_license():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$u=User::factory()->create(['role_id'=>$role]);$this->actingAs($u);$t=LegalEntity::create(['user_id'=>$u->id,'name'=>'Kadro','tax_number'=>'5757575757','is_active'=>true]);app(TenantContext::class)->set($t);HrLicense::create(['legal_entity_id'=>$t->id,'module_key'=>'analitik','is_active'=>true]);$this->get(route('hr.workforce-planning'))->assertOk()->assertSee('Kadro ve Bütçe Planlama');}}
